import{_ as o,o as a,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"🛠️ 管理員指令與商店管理","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Admin-Management.md","filePath":"Mc-Admin-Management.md"}'),r={name:"Mc-Admin-Management.md"};function i(l,e,d,s,c,h){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="🛠️-管理員指令與商店管理" tabindex="-1">🛠️ 管理員指令與商店管理 <a class="header-anchor" href="#🛠️-管理員指令與商店管理" aria-label="Permalink to &quot;🛠️ 管理員指令與商店管理&quot;">​</a></h1><p>本章節列出伺服器管理員（OP）專用的維護與管理指令，用於監控全服商店與解決糾紛。</p><hr><h2 id="🏪-1-管理員無限商店設定" tabindex="-1">🏪 1. 管理員無限商店設定 <a class="header-anchor" href="#🏪-1-管理員無限商店設定" aria-label="Permalink to &quot;🏪 1. 管理員無限商店設定&quot;">​</a></h2><p>管理員可以建立免庫存、免資金的無限商店：</p><ol><li>按照常規方式建立商店，或對著現有商店告示牌點選 <strong>【右鍵】</strong> 開啟管理面板。</li><li>點選 <strong>「無限模式 (Infinite Mode)」</strong> 旁邊的 <code>[修改]</code> 將其啟用。</li><li>啟用後，商店庫存會顯示為 <code>無限</code>，玩家可以無限制地進行交易。</li><li><strong>遠端補貨與清空</strong>：無限商店的管理面板會額外解鎖 <code>遠端補貨</code> 與 <code>清空商品</code> 的 <code>[執行]</code> 按鈕，點擊可快速操作。</li></ol><hr><h2 id="⚙️-2-全局管理與糾紛處理指令" tabindex="-1">⚙️ 2. 全局管理與糾紛處理指令 <a class="header-anchor" href="#⚙️-2-全局管理與糾紛處理指令" aria-label="Permalink to &quot;⚙️ 2. 全局管理與糾紛處理指令&quot;">​</a></h2><ul><li><strong><code>/shop list</code></strong>：列出全服所有商店的詳細資訊與擁有者。</li><li><strong><code>/shop reload</code></strong>：重新載入商店資料檔與設定檔。</li><li><strong>強拆商店</strong>：管理員可以直接破壞任何玩家的商店告示牌，系統會強制註銷並清理該位置的商店數據。</li></ul>',9)])])}const g=o(r,[["render",i]]);export{m as __pageData,g as default};
